INSERT INTO `email_templates` (`id`, `company_id`, `template_code`, `template_name`, `module`, `document_type`, `event_code`, `subject_template`, `body_template`, `is_html`, `is_active`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES
(1, NULL, 'SALES_QUOTATION_SENT', 'Sales Quotation Sent', 'sales', 'sales_quotation', 'quotation_sent', 'Quotation {{document_no}} from Billing ERP', '<p>Dear {{party_name}},</p><p>Your quotation <strong>{{document_no}}</strong> dated {{document_date}} is ready.</p><p>Total amount: {{total_amount}}</p>', 1, 1, NULL, NULL, '2026-05-05 11:01:43', '2026-05-05 11:01:43'),
(2, NULL, 'SALES_INVOICE_POSTED', 'Sales Invoice Posted', 'sales', 'sales_invoice', 'sales_invoice_posted', 'Invoice {{document_no}} posted', '<p>Dear {{party_name}},</p><p>Your invoice <strong>{{document_no}}</strong> dated {{document_date}} has been posted.</p><p>Total amount: {{total_amount}}</p>', 1, 1, NULL, NULL, '2026-05-05 11:01:43', '2026-05-05 11:01:43'),
(3, NULL, 'PURCHASE_ORDER_CONFIRMED', 'Purchase Order Confirmed', 'purchase', 'purchase_order', 'purchase_order_confirmed', 'Purchase Order {{document_no}} confirmed', '<p>Dear {{party_name}},</p><p>Purchase order <strong>{{document_no}}</strong> dated {{document_date}} has been confirmed.</p><p>Total amount: {{total_amount}}</p>', 1, 1, NULL, NULL, '2026-05-05 11:01:43', '2026-05-05 11:01:43'),
(4, NULL, 'PURCHASE_INVOICE_POSTED', 'Purchase Invoice Posted', 'purchase', 'purchase_invoice', 'purchase_invoice_posted', 'Purchase Invoice {{document_no}} booked', '<p>Dear {{party_name}},</p><p>Purchase invoice <strong>{{document_no}}</strong> dated {{document_date}} has been booked.</p><p>Total amount: {{total_amount}}</p>', 1, 1, NULL, NULL, '2026-05-05 11:01:43', '2026-05-05 11:01:43'),
(5, NULL, 'SERVICE_TICKET_CREATED', 'Service Ticket Created', 'service', 'service_ticket', 'service_ticket_created', 'Service ticket {{document_no}} created', '<p>Hello,</p><p>Service ticket <strong>{{document_no}}</strong> has been created.</p><p>Issue: {{issue_title}}</p>', 1, 1, NULL, NULL, '2026-05-05 11:01:43', '2026-05-05 11:01:43'),
(6, NULL, 'LEAVE_REQUEST_SUBMITTED', 'Leave Request Submitted', 'hr', 'leave_request', 'leave_request_submitted', 'Leave request submitted', '<p>Hello,</p><p>A leave request has been submitted.</p><p>Status: {{status}}</p><p>Notes: {{notes}}</p>', 1, 1, NULL, NULL, '2026-05-05 11:01:43', '2026-05-05 11:01:43'),
(7, NULL, 'LEAVE_REQUEST_APPROVED', 'Leave Request Approved', 'hr', 'leave_request', 'leave_request_approved', 'Leave request approved', '<p>Hello,</p><p>Your leave request has been approved.</p><p>Status: {{status}}</p></p>', 1, 1, NULL, NULL, '2026-05-05 11:01:43', '2026-05-05 11:01:43'),
(8, NULL, 'PAYSLIP_GENERATED', 'Payslip Generated', 'hr', 'payslip', 'payslip_generated', 'Payslip {{document_no}} generated', '<p>Hello,</p><p>Your payslip <strong>{{document_no}}</strong> has been generated.</p><p>Net salary: {{total_amount}}</p>', 1, 1, NULL, NULL, '2026-05-05 11:01:43', '2026-05-05 11:01:43');;
